document.addEventListener("DOMContentLoaded",function(){new Swiper(".about-page-journey-slider",{slidesPerView:"auto",speed:1500,spaceBetween:24,autoplay:{delay:2500,pauseOnMouseEnter:!0,disableOnInteraction:!1},breakpoints:{280:{slidesPerView:1},350:{slidesPerView:2,spaceBetween:10},576:{slidesPerView:3},768:{slidesPerView:4,spaceBetween:10},992:{slidesPerView:5,spaceBetween:15},1200:{slidesPerView:6,spaceBetween:10},1400:{slidesPerView:6}}});const s=document.querySelectorAll(".about-page-journey-slider .nav-link"),a=document.querySelectorAll(".journey-pane");s.forEach(n=>{n.addEventListener("click",function(){var t;s.forEach(e=>e.classList.remove("active")),this.classList.add("active");const i=this.dataset.target;a.forEach(e=>e.classList.remove("active")),(t=document.querySelector(`[data-content="${i}"]`))==null||t.classList.add("active")})})});
